import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";

const [specArg = "../../openapi/qaflow.openapi.json", outputArg = "src/app/api/generated/qaflowClient.ts"] =
  process.argv.slice(2);

const specPath = resolve(process.cwd(), specArg);
const outputPath = resolve(process.cwd(), outputArg);
const spec = JSON.parse(await readFile(specPath, "utf8"));
const schemas = spec.components?.schemas ?? {};
const methods = ["get", "post", "put", "patch", "delete"];

const lines = [
  "/* eslint-disable */",
  "// Generated by scripts/generate-openapi-client.mjs. Do not edit by hand.",
  "",
  'const API_BASE_URL = import.meta.env.VITE_API_BASE_URL ?? "";',
  ""
];

for (const [name, schema] of Object.entries(schemas)) {
  lines.push(renderSchema(name, schema), "");
}

for (const [path, pathItem] of Object.entries(spec.paths ?? {})) {
  for (const method of methods) {
    const operation = pathItem?.[method];
    if (!operation?.operationId) {
      continue;
    }
    lines.push(renderOperation(path, method, operation), "");
  }
}

lines.push(renderRuntime());

await mkdir(dirname(outputPath), { recursive: true });
await writeFile(outputPath, `${lines.join("\n").trimEnd()}\n`, "utf8");

function renderSchema(name, schema) {
  if (schema.type === "object" || schema.properties || schema.additionalProperties) {
    const body = renderObjectBody(schema);
    return `export interface ${name} {\n${body}\n}`;
  }

  return `export type ${name} = ${schemaToType(schema)};`;
}

function renderObjectBody(schema) {
  const required = new Set(schema.required ?? []);
  const properties = schema.properties ?? {};
  const body = Object.entries(properties).map(([propertyName, propertySchema]) => {
    const optional = required.has(propertyName) ? "" : "?";
    return `  ${quoteProperty(propertyName)}${optional}: ${schemaToType(propertySchema)};`;
  });

  if (schema.additionalProperties) {
    body.push(`  [key: string]: ${schemaToType(schema.additionalProperties)};`);
  }

  return body.length ? body.join("\n") : "  [key: string]: unknown;";
}

function renderOperation(path, method, operation) {
  const params = (operation.parameters ?? []).filter((parameter) => parameter.in === "path");
  const response = responseType(operation);
  const args = ["accessToken: string", ...params.map((parameter) => `${parameter.name}: string`)];
  const init = method === "get" ? "" : `, { method: "${method.toUpperCase()}" }`;
  const requestFn = response.kind === "text" ? "requestText" : `requestJson<${response.type}>`;

  return `export function ${operation.operationId}(${args.join(", ")}): Promise<${response.type}> {
  return ${requestFn}(${pathExpression(path, params)}, accessToken${init});
}`;
}

function responseType(operation) {
  const response = operation.responses?.["200"] ?? operation.responses?.["201"] ?? operation.responses?.["204"];
  const content = response?.content ?? {};
  const jsonContent = content["application/json"] ?? content["*/*"];
  const textContent = content["text/html"] ?? content["text/plain"];

  if (textContent && !jsonContent) {
    return { kind: "text", type: "string" };
  }

  if (jsonContent?.schema) {
    const type = schemaToType(jsonContent.schema);
    if (type === "string" && operation.operationId.toLowerCase().includes("html")) {
      return { kind: "text", type: "string" };
    }
    return { kind: "json", type };
  }

  return { kind: "json", type: "unknown" };
}

function schemaToType(schema) {
  if (!schema) {
    return "unknown";
  }

  if (schema.$ref) {
    return nullable(refName(schema.$ref), schema);
  }

  if (schema.oneOf || schema.anyOf) {
    const variants = schema.oneOf ?? schema.anyOf;
    return nullable(variants.map(schemaToType).join(" | "), schema);
  }

  if (schema.enum) {
    return nullable(schema.enum.map((value) => JSON.stringify(value)).join(" | "), schema);
  }

  if (schema.type === "array") {
    return nullable(`${schemaToType(schema.items)}[]`, schema);
  }

  if (schema.type === "integer" || schema.type === "number") {
    return nullable("number", schema);
  }

  if (schema.type === "boolean") {
    return nullable("boolean", schema);
  }

  if (schema.type === "string") {
    return nullable("string", schema);
  }

  if (schema.type === "object" || schema.properties || schema.additionalProperties) {
    if (schema.additionalProperties && !schema.properties) {
      return nullable(`Record<string, ${schemaToType(schema.additionalProperties)}>`, schema);
    }
    return nullable(`{\n${renderObjectBody(schema)}\n}`, schema);
  }

  return nullable("unknown", schema);
}

function nullable(type, schema) {
  return schema.nullable ? `${type} | null` : type;
}

function refName(ref) {
  return ref.split("/").at(-1);
}

function quoteProperty(name) {
  return /^[A-Za-z_$][\w$]*$/.test(name) ? name : JSON.stringify(name);
}

function pathExpression(path, params) {
  let expression = path.replaceAll("`", "\\`");
  for (const parameter of params) {
    expression = expression.replaceAll(`{${parameter.name}}`, `\${encodeURIComponent(${parameter.name})}`);
  }
  return `\`${expression}\``;
}

function renderRuntime() {
  return `async function requestJson<T>(path: string, accessToken: string, init: RequestInit = {}): Promise<T> {
  const response = await request(path, accessToken, init);
  return response.json() as Promise<T>;
}

async function requestText(path: string, accessToken: string, init: RequestInit = {}): Promise<string> {
  const response = await request(path, accessToken, init);
  return response.text();
}

async function request(path: string, accessToken: string, init: RequestInit = {}): Promise<Response> {
  const response = await fetch(\`\${API_BASE_URL}\${path}\`, {
    ...init,
    headers: {
      ...(init.body ? { "Content-Type": "application/json" } : {}),
      Authorization: \`Bearer \${accessToken}\`,
      ...init.headers
    }
  });

  if (!response.ok) {
    throw new Error(await errorMessage(response));
  }

  return response;
}

async function errorMessage(response: Response): Promise<string> {
  try {
    const payload = (await response.json()) as { message?: string };
    return payload.message ?? \`Request failed with status \${response.status}\`;
  } catch {
    return \`Request failed with status \${response.status}\`;
  }
}`;
}
